@dataclass
class SecurityConfig:
    """Security configuration to prevent model inversion attacks."""
    # Minimum confidence threshold - scores below this are suppressed
    min_confidence_threshold: float = 0.3
    # Add calibrated noise to confidence scores (differential privacy)
    dp_noise_scale: float = 0.02
    # Maximum number of results returned per query
    max_results_per_query: int = 10
    # Rate limiting: max queries per minute per API key
    rate_limit_per_minute: int = 30
    # Quantize confidence scores to reduce precision (number of decimal places)
    score_precision: int = 2
    # Minimum number of training samples per class
    min_samples_per_class: int = 1
    # API key length
    api_key_length: int = 32
    # Enable score clamping (prevent extreme confidence values)
    clamp_max_score: float = 0.99
    clamp_min_score: float = 0.01


SECURITY_CONFIG = SecurityConfig()

# ============================================================
# Secure Score Processing (Anti-Model Inversion)
# ============================================================

class SecureScoreProcessor:
    """
    Processes raw similarity scores with security measures
    to prevent model inversion attacks.
    
    Techniques used:
    1. Differential privacy noise addition
    2. Score quantization (reduced precision)
    3. Score clamping
    4. Thresholding (suppress low-confidence results)
    5. Top-k limiting
    """
    
    def __init__(self, config: SecurityConfig):
        self.config = config
        self._rng = np.random.default_rng()
    
    def process_scores(
        self, 
        raw_scores: Dict[str, float],
        request_id: str
    ) -> Dict[str, float]:
        """
        Apply security transformations to raw confidence scores.
        
        Args:
            raw_scores: Dictionary mapping employee_id -> raw confidence score
            request_id: Unique request identifier for audit logging
            
        Returns:
            Secured confidence scores
        """
        if not raw_scores:
            return {}
        
        processed = {}
        
        for employee_id, score in raw_scores.items():
            secured_score = self._secure_single_score(score)
            if secured_score is not None:
                processed[employee_id] = secured_score
        
        # Sort by score descending and limit results
        sorted_scores = dict(
            sorted(processed.items(), key=lambda x: x[1], reverse=True)
            [:self.config.max_results_per_query]
        )
        
        # Normalize to ensure scores sum to <= 1.0 (probability distribution)
        total = sum(sorted_scores.values())
        if total > 1.0:
            sorted_scores = {
                k: round(v / total, self.config.score_precision) 
                for k, v in sorted_scores.items()
            }
        
        logger.info(
            f"Request {request_id}: Processed {len(raw_scores)} raw scores "
            f"into {len(sorted_scores)} secured scores"
        )
        
        return sorted_scores
    
    def _secure_single_score(self, score: float) -> Optional[float]:
        """Apply security transformations to a single score."""
        # 1. Threshold check
        if score < self.config.min_confidence_threshold:
            return None
        
        # 2. Add calibrated Laplace noise (differential privacy)
        noise = self._rng.laplace(0, self.config.dp_noise_scale)
        noisy_score = score + noise
        
        # 3. Clamp to valid range
        clamped = np.clip(
            noisy_score, 
            self.config.clamp_min_score, 
            self.config.clamp_max_score
        )
        
        # 4. Quantize (reduce precision)
        quantized = round(float(clamped), self.config.score_precision)
        
        return quantized


# ============================================================
# Rate Limiter
# ============================================================

class RateLimiter:
    """Simple in-memory rate limiter."""
    
    def __init__(self, max_per_minute: int):
        self.max_per_minute = max_per_minute
        self._requests: Dict[str, List[float]] = {}
    
    def is_allowed(self, key: str) -> bool:
        """Check if a request is allowed for the given key."""
        now = time.time()
        window_start = now - 60.0
        
        if key not in self._requests:
            self._requests[key] = []
        
        # Clean old entries
        self._requests[key] = [
            t for t in self._requests[key] if t > window_start
        ]
        
        if len(self._requests[key]) >= self.max_per_minute:
            return False
        
        self._requests[key].append(now)
        return True


# ============================================================
# Face Encoding Store (Secure Storage)
# ============================================================

class FaceEncodingStore:
    """
    Securely stores face encodings for known employees.
    Encodings are stored in memory with access controls.
    """
    
    def __init__(self):
        self._encodings: Dict[str, List[np.ndarray]] = {}
        self._metadata: Dict[str, Dict] = {}
        self._encoding_hash: Optional[str] = None
    
    def add_encoding(
        self, 
        employee_id: str, 
        encoding: np.ndarray,
        metadata: Optional[Dict] = None
    ) -> None:
        """Add a face encoding for an employee."""
        if employee_id not in self._encodings:
            self._encodings[employee_id] = []
            self._metadata[employee_id] = metadata or {}
        
        self._encodings[employee_id].append(encoding.copy())
        self._encoding_hash = None  # Invalidate cache
        
        logger.info(
            f"Added encoding for employee {employee_id}. "
            f"Total encodings: {len(self._encodings[employee_id])}"
        )
    
    def get_all_encodings(self) -> Tuple[List[np.ndarray], List[str]]:
        """Get all encodings and their corresponding employee IDs."""
        encodings = []
        labels = []
        
        for employee_id, encs in self._encodings.items():
            for enc in encs:
                encodings.append(enc)
                labels.append(employee_id)
        
        return encodings, labels
    
    def get_employee_ids(self) -> List[str]:
        """Get list of all registered employee IDs."""
        return list(self._encodings.keys())
    
    def get_employee_count(self) -> int:
        """Get number of registered employees."""
        return len(self._encodings)
    
    def get_encoding_count(self, employee_id: str) -> int:
        """Get number of encodings for a specific employee."""
        return len(self._encodings.get(employee_id, []))
    
    def remove_employee(self, employee_id: str) -> bool:
        """Remove all encodings for an employee."""
        if employee_id in self._encodings:
            del self._encodings[employee_id]
            del self._metadata[employee_id]
            self._encoding_hash = None
            logger.info(f"Removed all encodings for employee {employee_id}")
            return True
        return False
    
    def get_integrity_hash(self) -> str:
        """Get a hash of all stored encodings for integrity verification."""
        if self._encoding_hash is None:
            hasher = hashlib.sha256()
            for emp_id in sorted(self._encodings.keys()):
                hasher.update(emp_id.encode())
                for enc in self._encodings[emp_id]:
                    hasher.update(enc.tobytes())
            self._encoding_hash = hasher.hexdigest()
        return self._encoding_hash


