class FacialRecognitionModel:
    """
    Facial recognition model using face_recognition library.
    Computes similarity scores between query faces and stored encodings.
    """
    
    def __init__(
        self, 
        store: FaceEncodingStore,
        score_processor: SecureScoreProcessor
    ):
        self.store = store
        self.score_processor = score_processor
    
    def train_from_directory(self, training_dir: str) -> Dict[str, int]:
        """
        Train the model from a directory of employee photos.
        
        Expected directory structure:
        training_dir/
            employee_001/
                photo1.jpg
                photo2.jpg
            employee_002/
                photo1.jpg
        
        Returns:
            Dictionary mapping employee_id -> number of encodings added
        """
        training_path = Path(training_dir)
        if not training_path.exists():
            raise FileNotFoundError(f"Training directory not found: {training_dir}")
        
        results = {}
        
        for employee_dir in sorted(training_path.iterdir()):
            if not employee_dir.is_dir():
                continue
            
            employee_id = employee_dir.name
            count = 0
            
            for image_file in sorted(employee_dir.iterdir()):
                if image_file.suffix.lower() not in {'.jpg', '.jpeg', '.png', '.bmp'}:
                    continue
                
                try:
                    image = face_recognition.load_image_file(str(image_file))
                    encodings = face_recognition.face_encodings(image)
                    
                    if len(encodings) == 0:
                        logger.warning(
                            f"No face found in {image_file} for employee {employee_id}"
                        )
                        continue
                    
                    if len(encodings) > 1:
                        logger.warning(
                            f"Multiple faces found in {image_file} for employee "
                            f"{employee_id}. Using the first face only."
                        )
                    
                    self.store.add_encoding(
                        employee_id, 
                        encodings[0],
                        metadata={"source_file": image_file.name}
                    )
                    count += 1
                    
                except Exception as e:
                    logger.error(
                        f"Error processing {image_file} for employee "
                        f"{employee_id}: {e}"
                    )
            
            results[employee_id] = count
            logger.info(f"Employee {employee_id}: {count} face encodings extracted")
        
        return results
    
    def train_from_image_bytes(
        self, 
        employee_id: str, 
        image_bytes: bytes
    ) -> bool:
        """
        Add a training image from bytes for a specific employee.
        
        Returns:
            True if encoding was successfully extracted and stored
        """
        try:
            image = face_recognition.load_image_file(io.BytesIO(image_bytes))
            encodings = face_recognition.face_encodings(image)
            
            if len(encodings) == 0:
                logger.warning(f"No face found in uploaded image for {employee_id}")
                return False
            
            if len(encodings) > 1:
                logger.warning(
                    f"Multiple faces in uploaded image for {employee_id}. "
                    f"Using first face."
                )
            
            self.store.add_encoding(employee_id, encodings[0])
            return True
            
        except Exception as e:
            logger.error(f"Error processing uploaded image for {employee_id}: {e}")
            return False
    
    def recognize(
        self, 
        image_bytes: bytes,
        request_id: str
    ) -> Dict:
        """
        Recognize faces in an image and return secured confidence scores.
        
        Args:
            image_bytes: Raw image bytes
            request_id: Unique request ID for audit trail
            
        Returns:
            Dictionary with recognition results
        """
        try:
            image = face_recognition.load_image_file(io.BytesIO(image_bytes))
        except Exception as e:
            return {
                "success": False,
                "error": "Invalid image format",
                "request_id": request_id
            }
        
        # Detect faces in the query image
        face_locations = face_recognition.face_locations(image, model="hog")
        
        if len(face_locations) == 0:
            return {
                "success": True,
                "faces_detected": 0,
                "results": [],
                "request_id": request_id
            }
        
        # Get encodings for detected faces
        query_encodings = face_recognition.face_encodings(image, face_locations)
        
        # Get all known encodings
        known_encodings, known_labels = self.store.get_all_encodings()
        
        if len(known_encodings) == 0:
            return {
                "success": True,
                "faces_detected": len(face_locations),
                "results": [],
                "message": "No trained employees in the system",
                "request_id": request_id
            }
        
        results = []
        
        for idx, (query_enc, face_loc) in enumerate(
            zip(query_encodings, face_locations)
        ):
            # Compute face distances to all known encodings
            distances = face_recognition.face_distance(known_encodings, query_enc)
            
            # Convert distances to similarity scores per employee
            raw_scores = self._aggregate_scores(distances, known_labels)
            
            # Apply security processing
            secured_scores = self.score_processor.process_scores(
                raw_scores, request_id
            )
            
            # Determine best match
            best_match = None
            best_score = 0.0
            if secured_scores:
                best_match = max(secured_scores, key=secured_scores.get)
                best_score = secured_scores[best_match]
            
            top, right, bottom, left = face_loc
            
            face_result = {
                "face_index": idx,
                "bounding_box": {
                    "top": top,
                    "right": right,
                    "bottom": bottom,
                    "left": left
                },
                "best_match": {
                    "employee_id": best_match,
                    "confidence": best_score
                } if best_match else None,
                "probability_distribution": secured_scores,
                "is_known": best_match is not None and best_score >= 0.5
            }
            
            results.append(face_result)
        
        return {
            "success": True,
            "faces_detected": len(face_locations),
            "results": results,
            "request_id": request_id,
            "model_integrity_hash": self.store.get_integrity_hash()[:16]
        }
    
    def _aggregate_scores(
        self, 
        distances: np.ndarray, 
        labels: List[str]
    ) -> Dict[str, float]:
        """
        Aggregate face distances into per-employee confidence scores.
        
        Uses a softmax-like transformation of distances to produce
        a probability distribution over known employees.
        """
        # Convert distances to similarities (lower distance = higher similarity)
        # Using exponential decay: similarity = exp(-distance * scale)
        scale = 4.0  # Controls sharpness of the distribution
        similarities = np.exp(-distances * scale)
        
        # Aggregate by employee (take max similarity per employee)
        employee_scores: Dict[str, float] = {}
        employee_counts: Dict[str, int] = {}
        
        for sim, label in zip(similarities, labels):
            if label not in employee_scores:
                employee_scores[label] = 0.0
                employee_counts[label] = 0
            # Use max similarity across all encodings for this employee
            employee_scores[label] = max(employee_scores[label], float(sim))
            employee_counts[label] += 1
        
        # Normalize to create probability distribution
        total = sum(employee_scores.values())
        if total > 0:
            employee_scores = {
                k: v / total for k, v in employee_scores.items()
            }
        
        return employee_scores


