# API Key Management
# ============================================================

class APIKeyManager:
    """Simple API key management for authentication."""
    
    def __init__(self):
        self._keys: Dict[str, Dict] = {}
    
    def generate_key(self, description: str = "", role: str = "reader") -> str:
        """Generate a new API key."""
        key = secrets.token_hex(SECURITY_CONFIG.api_key_length)
        self._keys[key] = {
            "description": description,
            "role": role,
            "created_at": time.time(),
            "active": True
        }
        logger.info(f"Generated new API key for: {description} (role: {role})")
        return key
    
    def validate_key(self, key: str) -> Optional[Dict]:
        """Validate an API key and return its metadata."""
        if key in self._keys and self._keys[key]["active"]:
            return self._keys[key]
        return None
    
    def revoke_key(self, key: str) -> bool:
        """Revoke an API key."""
        if key in self._keys:
            self._keys[key]["active"] = False
            return True
        return False
    
    def has_role(self, key: str, required_role: str) -> bool:
        """Check if a key has the required role."""
        meta = self.validate_key(key)
        if meta is None:
            return False
        role_hierarchy = {"admin": 2, "trainer": 1, "reader": 0}
        return role_hierarchy.get(meta["role"], -1) >= role_hierarchy.get(required_role, 99)


