# Audit Logger
# ============================================================

class AuditLogger:
    """Logs security-relevant events for audit trail."""
    
    def __init__(self, log_file: str = "audit.log"):
        self._logger = logging.getLogger("audit")
        handler = logging.FileHandler(log_file)
        handler.setFormatter(
            logging.Formatter('%(asctime)s - AUDIT - %(message)s')
        )
        self._logger.addHandler(handler)
        self._logger.setLevel(logging.INFO)
    
    def log_recognition_request(
        self, 
        request_id: str, 
        api_key_hash: str,
        faces_detected: int,
        top_match: Optional[str],
        client_ip: str
    ):
        """Log a recognition request."""
        self._logger.info(
            f"RECOGNITION request_id={request_id} "
            f"api_key_hash={api_key_hash[:8]}... "
            f"faces={faces_detected} "
            f"top_match={top_match or 'none'} "
            f"client_ip={client_ip}"
        )
    
    def log_training_event(
        self, 
        employee_id: str, 
        api_key_hash: str,
        success: bool
    ):
        """Log a training event."""
        self._logger.info(
            f"TRAINING employee={employee_id} "
            f"api_key_hash={api_key_hash[:8]}... "
            f"success={success}"
        )
    
    def log_auth_failure(self, client_ip: str, endpoint: str):
        """Log an authentication failure."""
        self._logger.warning(
            f"AUTH_FAILURE client_ip={client_ip} endpoint={endpoint}"
        )
    
    def log_rate_limit(self, api_key_hash: str, client_ip: str):
        """Log a rate limit event."""
        self._logger.warning(
            f"RATE_LIMITED api_key_hash={api_key_hash[:8]}... "
            f"client_ip={client_ip}"
        )


