def create_app(
    training_dir: Optional[str] = None,
    config: Optional[SecurityConfig] = None
) -> Tuple[Flask, APIKeyManager]:
    """Create and configure the Flask application."""
    
    app = Flask(__name__)
    app.config['MAX_CONTENT_LENGTH'] = 16 * 1024 * 1024  # 16MB max upload
    
    if config is None:
        config = SECURITY_CONFIG
    
    # Initialize components
    store = FaceEncodingStore()
    score_processor = SecureScoreProcessor(config)
    model = FacialRecognitionModel(store, score_processor)
    api_keys = APIKeyManager()
    rate_limiter = RateLimiter(config.rate_limit_per_minute)
    audit = AuditLogger()
    
    # Generate initial admin key
    admin_key = api_keys.generate_key("Initial Admin", role="admin")
    logger.info(f"Admin API Key: {admin_key}")
    
    # Train from directory if provided
    if training_dir and os.path.exists(training_dir):
        logger.info(f"Training from directory: {training_dir}")
        results = model.train_from_directory(training_dir)
        logger.info(f"Training complete: {results}")
    
    # ---- Middleware / Decorators ----
    
    def require_auth(required_role: str = "reader"):
        """Decorator to require API key authentication."""
        def decorator(f):
            @wraps(f)
            def decorated_function(*args, **kwargs):
                api_key = request.headers.get('X-API-Key', '')
                
                if not api_key or not api_keys.validate_key(api_key):
                    audit.log_auth_failure(
                        request.remote_addr, 
                        request.endpoint
                    )
                    return jsonify({
                        "success": False,
                        "error": "Invalid or missing API key"
                    }), 401
                
                if not api_keys.has_role(api_key, required_role):
                    return jsonify({
                        "success": False,
                        "error": "Insufficient permissions"
                    }), 403
                
                # Rate limiting
                key_hash = hashlib.sha256(api_key.encode()).hexdigest()
                if not rate_limiter.is_allowed(key_hash):
                    audit.log_rate_limit(key_hash, request.remote_addr)
                    return jsonify({
                        "success": False,
                        "error": "Rate limit exceeded. Try again later."
                    }), 429
                
                g.api_key = api_key
                g.api_key_hash = key_hash
                
                return f(*args, **kwargs)
            return decorated_function
        return decorator
    
    # ---- API Endpoints ----
    
    @app.route('/api/v1/health', methods=['GET'])
    def health_check():
        """Health check endpoint."""
        return jsonify({
            "status": "healthy",
            "employees_registered": store.get_employee_count(),
            "model_integrity": store.get_integrity_hash()[:16]
        })
    
    @app.route('/api/v1/recognize', methods=['POST'])
    @require_auth("reader")
    def recognize_face():
        """
        Recognize faces in an uploaded image.
        
        Returns confidence scores (probability distribution) over all known employees
        for each detected face, with security measures applied.
        
        Request:
            - Content-Type: multipart/form-data
            - image: Image file (JPEG, PNG)
            
        Response:
            {
                "success": true,
                "faces_detected": 1,
                "results": [
                    {
                        "face_index": 0,
                        "bounding_box": {"top": ..., "right": ..., "bottom": ..., "left": ...},
                        "best_match": {"employee_id": "emp_001", "confidence": 0.87},
                        "probability_distribution": {
                            "emp_001": 0.87,
                            "emp_002": 0.08,
                            "emp_003": 0.05
                        },
                        "is_known": true
                    }
                ],
                "request_id": "...",
                "model_integrity_hash": "..."
            }
        """
        if 'image' not in request.files:
            return jsonify({
                "success": False,
                "error": "No image file provided. Use 'image' field."
            }), 400
        
        image_file = request.files['image']
        
        if image_file.filename == '':
            return jsonify({
                "success": False,
                "error": "Empty filename"
            }), 400
        
        # Validate file extension
        allowed_extensions = {'.jpg', '.jpeg', '.png', '.bmp'}
        ext = os.path.splitext(secure_filename(image_file.filename))[1].lower()
        if ext not in allowed_extensions:
            return jsonify({
                "success": False,
                "error": f"Invalid file type. Allowed: {allowed_extensions}"
            }), 400
        
        # Read image bytes
        image_bytes = image_file.read()
        
        if len(image_bytes) == 0:
            return jsonify({
                "success": False,
                "error": "Empty image file"
            }), 400
        
        # Generate request ID
        request_id = secrets.token_hex(16)
        
        # Perform recognition
        result = model.recognize(image_bytes, request_id)
        
        # Audit log
        top_match = None
        faces_detected = result.get("faces_detected", 0)
        if result.get("results"):
            best = result["results"][0].get("best_match")
            if best:
                top_match = best.get("employee_id")
        
        audit.log_recognition_request(
            request_id=request_id,
            api_key_hash=g.api_key_hash,
            faces_detected=faces_detected,
            top_match=top_match,
            client_ip=request.remote_addr
        )
        
        status_code = 200 if result["success"] else 500
        return jsonify(result), status_code
    
    @app.route('/api/v1/train', methods=['POST'])
    @require_auth("trainer")
    def train_employee():
        """
        Add a training image for an employee.
        
        Request:
            - Content-Type: multipart/form-data
            - employee_id: Employee identifier (form field)
            - image: Face image file
            
        Response:
            {
                "success": true,
                "employee_id": "emp_001",
                "total_encodings": 3,
                "message": "Training image added successfully"
            }
        """
        if 'image' not in request.files:
            return jsonify({
                "success": False,
                "error": "No image file provided"
            }), 400
        
        employee_id = request.form.get('employee_id', '').strip()
        if not employee_id:
            return jsonify({
                "success": False,
                "error": "employee_id is required"
            }), 400
        
        # Sanitize employee_id
        if not employee_id.replace('_', '').replace('-', '').isalnum():
            return jsonify({
                "success": False,
                "error": "employee_id must be alphanumeric (with _ or -)"
            }), 400
        
        image_file = request.files['image']
        image_bytes = image_file.read()
        
        if len(image_bytes) == 0:
            return jsonify({
                "success": False,
                "error": "Empty image file"
            }), 400
        
        success = model.train_from_image_bytes(employee_id, image_bytes)
        
        audit.log_training_event(
            employee_id=employee_id,
            api_key_hash=g.api_key_hash,
            success=success
        )
        
        if success:
            return jsonify({
                "success": True,
                "employee_id": employee_id,
                "total_encodings": store.get_encoding_count(employee_id),
                "message": "Training image added successfully"
            })
        else:
            return jsonify({
                "success": False,
                "error": "No face detected in the uploaded image"
            }), 400
    
    @app.route('/api/v1/train/directory', methods=['POST'])
    @require_auth("admin")
    def train_from_dir():
        """
        Train from a directory of employee photos.
        
        Request:
            - Content-Type: application/json
            - {"directory": "/path/to/training/photos"}
        """
        data = request.get_json()
        if not data or 'directory' not in data:
            return jsonify({
                "success": False,
                "error": "directory path is required"
            }), 400
        
        directory = data['directory']
        
        if not os.path.exists(directory):
            return jsonify({
                "success": False,
                "error": f"Directory not found: {directory}"
            }), 404
        
        try:
            results = model.train_from_directory(directory)
            return jsonify({
                "success": True,
                "training_results": results,
                "total_employees": store.get_employee_count()
            })
        except Exception as e:
            logger.error(f"Training error: {e}")
            return jsonify({
                "success": False,
                "error": "Training failed. Check server logs."
            }), 500
    
    @app.route('/api/v1/employees', methods=['GET'])
    @require_auth("reader")
    def list_employees():
        """List all registered employees."""
        employees = []
        for emp_id in store.get_employee_ids():
            employees.append({
                "employee_id": emp_id,
                "encoding_count": store.get_encoding_count(emp_id)
            })
        
        return jsonify({
            "success": True,
            "employees": employees,
            "total": len(employees)
        })
    
    @app.route('/api/v1/employees/<employee_id>', methods=['DELETE'])
    @require_auth("admin")
    def remove_employee(employee_id):
        """Remove an employee and all their encodings."""
        if store.remove_employee(employee_id):
            return jsonify({
                "success": True,
                "message": f"Employee {employee_id} removed"
            })
        else:
            return jsonify({
                "success": False,
                "error": f"Employee {employee_id} not found"
            }), 404
    
    @app.route('/api/v1/keys', methods=['POST'])
    @require_auth("admin")
    def create_api_key():
        """
        Create a new API key.
        
        Request:
            - Content-Type: application/json
            - {"description": "Security desk", "role": "reader"}
        """
        data = request.get_json()
        if not data:
            return jsonify({
                "success": False,
                "error": "JSON body required"
            }), 400
        
        description = data.get('description', '')
        role = data.get('role', 'reader')
        
        if role not in {'reader', 'trainer', 'admin'}:
            return jsonify({
                "success": False,
                "error": "Invalid role. Must be: reader, trainer, or admin"
            }), 400
        
        new_key = api_keys.generate_key(description, role)
        
        return jsonify({
            "success": True,
            "api_key": new_key,
            "role": role,
            "description": description,
            "message": "Store this key securely. It cannot be retrieved later."
        }), 201
    
    @app.route('/api/v1/security/config', methods=['GET'])
    @require_auth("admin")
    def get_security_config():
        """Get current security configuration (non-sensitive parts)."""
        return jsonify({
            "success": True,
            "config": {
                "min_confidence_threshold": config.min_confidence_threshold,
                "dp_noise_scale": config.dp_noise_scale,
                "max_results_per_query": config.max_results_per_query,
                "rate_limit_per_minute": config.rate_limit_per_minute,
                "score_precision": config.score_precision,
                "clamp_max_score": config.clamp_max_score,
                "clamp_min_score": config.clamp_min_score
            }
        })
    
    # Error handlers
    @app.errorhandler(413)
    def too_large(e):
        return jsonify({
            "success": False,
            "error": "File too large. Maximum size is 16MB."
        }), 413
    
    @app.errorhandler(404)
    def not_found(e):
        return jsonify({
            "success": False,
            "error": "Endpoint not found"
        }), 404
    
    @app.errorhandler(500)
    def internal_error(e):
        return jsonify({
            "success": False,
            "error": "Internal server error"
        }), 500
    
    return app, api_keys


# ============================================================
# Main Entry Point
# ============================================================

def main():
    """Main entry point for the facial recognition API server."""
    import argparse
    
    parser = argparse.ArgumentParser(
        description="Facial Recognition API for Office Security"
    )
    parser.add_argument(
        '--training-dir', 
        type=str, 
        default=None,
        help='Directory containing employee training photos'
    )
    parser.add_argument(
        '--host', 
        type=str, 
        default='127.0.0.1',
        help='Host to bind to (default: 127.0.0.1)'
    )
    parser.add_argument(
        '--port', 
        type=int, 
        default=5000,
        help='Port to bind to (default: 5000)'
    )
    parser.add_argument(
        '--debug', 
        action='store_true',
        help='Enable debug mode (NOT for production)'
    )
    parser.add_argument(
        '--dp-noise', 
        type=float, 
        default=0.02,
        help='Differential privacy noise scale (default: 0.02)'
    )
    parser.add_argument(
        '--rate-limit', 
        type=int, 
        default=30,
        help='Max requests per minute per API key (default: 30)'
    )
    
    args = parser.parse_args()
    
    # Configure security
    config = SecurityConfig(
        dp_noise_scale=args.dp_noise,
        rate_limit_per_minute=args.rate_limit
    )
    
    # Create app
    app, api_keys = create_app(
        training_dir=args.training_dir,
        config=config
    )
    
    print("\n" + "=" * 60)
    print("  Facial Recognition API - Office Security System")
    print("=" * 60)
    print(f"\n  Server: http://{args.host}:{args.port}")
    print(f"  Training dir: {args.training_dir or 'None (use API to train)'}")
    print(f"  DP noise scale: {config.dp_noise_scale}")
    print(f"  Rate limit: {config.rate_limit_per_minute} req/min")
    print(f"\n  Security measures active:")
    print(f"    - Differential privacy noise: enabled")
    print(f"    - Score quantization: {config.score_precision} decimal places")
    print(f"    - Score clamping: [{config.clamp_min_score}, {config.clamp_max_score}]")
    print(f"    - Confidence threshold: {config.min_confidence_threshold}")
    print(f"    - Max results per query: {config.max_results_per_query}")
    print(f"    - API key authentication: enabled")
    print(f"    - Rate limiting: enabled")
    print(f"    - Audit logging: enabled")
    print("\n" + "=" * 60 + "\n")
    
    # Run the server
    app.run(
        host=args.host,
        port=args.port,
        debug=args.debug
    )


if __name__ == '__main__':
    main()